class Solution:
    def maxProduct(self, nums):
        ans = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                if nums[i] & nums[j] == 0:
                    p = nums[i] * nums[j]
                    if p > ans:
                        ans = p
        return ans

