class Solution:
    def maxProduct(self, nums):
        B = max(x.bit_length() for x in nums)
        FULL = (1 << B) - 1
        f = [0] * (1 << B)
        for x in nums:
            if x > f[x]:
                f[x] = x
        for b in range(B):
            bit = 1 << b
            for m in range(1 << B):
                if m & bit and f[m ^ bit] > f[m]:
                    f[m] = f[m ^ bit]
        ans = 0
        for x in nums:
            partner = f[FULL ^ x]
            if partner > 0:
                p = x * partner
                if p > ans:
                    ans = p
        return ans

