var maxProduct = function(nums) {
    let B = 1;
    for (const x of nums) B = Math.max(B, 32 - Math.clz32(x));
    const FULL = (1 << B) - 1;
    const f = new Array(1 << B).fill(0);
    for (const x of nums) if (x > f[x]) f[x] = x;
    for (let b = 0; b < B; b++) {
        const bit = 1 << b;
        for (let m = 0; m < (1 << B); m++) {
            if ((m & bit) && f[m ^ bit] > f[m]) f[m] = f[m ^ bit];
        }
    }
    let ans = 0;
    for (const x of nums) {
        const partner = f[FULL ^ x];
        if (partner > 0) {
            const p = x * partner;
            if (p > ans) ans = p;
        }
    }
    return ans;
};
